import UIKit
import Security

class BankingAppModule: NSObject {
    // MARK: - Properties

    var accountBalance: Double = 0

    // MARK: - Initialization

    override init() {
        super.init()

        self.accountBalance = loadAccountBalance()
    }

    deinit {
        saveAccountBalance(self.accountBalance)
    }

    // MARK: - Account Management

    func deposit(amount: Double) {
        let newBalance = self.accountBalance + amount
        self.accountBalance = newBalance
        saveAccountBalance(newBalance)
    }

    func withdraw(amount: Double) {
        if (amount > self.accountBalance) {
            return // insufficient funds
        }

        let newBalance = self.accountBalance - amount
        self.accountBalance = newBalance
        saveAccountBalance(newBalance)
    }

    // MARK: - Data Encryption

    func encryptData() {
        let data = "secret_data".data(using: .utf8)!
        let encryptedData = try! SecKeyEncrypt(kSecAttrAccessibleAfterFirstUnlock, data)

        print("Encrypted data: \(encryptedData)")
    }
}